#!/bin/bash
# =============================================================================
# CAMEL Annotation — HTCondor Wrapper for llama-3.3-70b
# =============================================================================
# Model: casperhansen/llama-3.3-70b-instruct-awq
# Origin: Western (Meta, USA)
# GPUs: 2 (TP=2)
# Auto-generated by generate_batch_jobs.py
# =============================================================================

set -euo pipefail

CHUNK_FILE="$1"
RESULT_FILE="$2"

echo "============================================================"
echo "CAMEL Annotation — llama-3.3-70b"
echo "============================================================"
echo "  Chunk:    ${CHUNK_FILE}"
echo "  Output:   ${RESULT_FILE}"
echo "  Model:    casperhansen/llama-3.3-70b-instruct-awq"
echo "  GPUs:     2 (TP=2)"
echo "  Host:     $(hostname)"
echo "  Date:     $(date)"
echo "============================================================"

# Setup conda
source "${HOME}/miniconda3/etc/profile.d/conda.sh"
conda activate "camel-annotation"

# Verify files
for f in "${CHUNK_FILE}" "${HOME}/vllm-openai.sif" "config2.yaml"; do
    if [ ! -f "$f" ]; then
        echo "ERROR: File not found: $f"
        exit 1
    fi
done

# Run annotation
python camel_annotate_hpc.py \
    "${CHUNK_FILE}" \
    "${RESULT_FILE}" \
    --model "casperhansen/llama-3.3-70b-instruct-awq" \
    --config "config2.yaml" \
    --container "${HOME}/vllm-openai.sif" \
    --quantization "awq_marlin" \
    --tp 2 \
    --threads 16 \
    --port 8900

echo "Job finished with exit code: $?"
echo "Date: $(date)"
